// Given a string grid representing the grid layout
// and an integer n representing the number of rows,
// calculate the height of each row and return the result as a string.
function solve(grid, n) {
  const rows = grid.split('\n');
  const heights = [];
  for (const row of rows) {
    const elements = row.split(' ');
    let max = 0;
    for (const element of elements) {
      max = Math.max(max, parseInt(element));
    }
    heights.push(max);
  }
  return heights.join('\n');
}

