class Solution:
  def solve(self, grid, n):
    rows = grid.split('\n')
    heights = []
    for row in rows:
      elements = row.split(' ')
      max = 0
      for element in elements:
        max = max(max, int(element))
      heights.append(max)
    return '\n'.join(map(str, heights))

